import { concatenarTabelas, intervaloCompetencias, TCelula, TTabela } from "@cecalc/utils";
import type { IDadosHiscre, IDadosPagamentoHiscre, ITabelasHiscre, TResumoHiscre } from "./tipos";

/**
 * Significado dos códigos:
 * 101 - Valor Total de MR do Período
 * 104 - Valor do Décimo Terceiro Salário
 * 105 - Salário-Família
 * 110 - Correção Monetária de Crédito Concessão
 * 137 - Adiantamento para Arredondamento
 * 215 - Saldo Arredondamento de Créditos
 * 316 - Saldo Devedor Arredondamento
 * 337 - CP Reativação
 */

function valorCodigo(pagamento: IDadosPagamentoHiscre, codigo: number): number {
  if (Array.isArray(pagamento.discriminacao)) {
    return pagamento.discriminacao.reduce((total, item) => item.codigo === codigo ? total + item.valor : total, 0)
  }
  return 0
}

function dadosDesconto(pagamento: IDadosPagamentoHiscre): [number, number] {
  const renda = valorCodigo(pagamento, 101);
  const abono = valorCodigo(pagamento, 104);
  return [renda, abono];
}

function dadosNovaPagina(pagamento: IDadosPagamentoHiscre): [number, number, number, number, number, number, number, number] {
  const cod101 = valorCodigo(pagamento, 101);
  const cod104 = valorCodigo(pagamento, 104);
  const cod105 = valorCodigo(pagamento, 105);
  const cod110 = valorCodigo(pagamento, 110);
  const cod137 = valorCodigo(pagamento, 137);
  const cod215 = valorCodigo(pagamento, 215);
  const cod316 = valorCodigo(pagamento, 316);
  const cod337 = valorCodigo(pagamento, 337);
  return [cod101, cod104, cod105, cod110, cod137, cod215, cod316, cod337];
}

export default function gerarTabelas(dados: IDadosHiscre): ITabelasHiscre {

  const info: TTabela<TCelula> = [
      ['NB:', dados.beneficio.nb ?? ''], 
      ['Segurado:',dados.beneficio.segurado ?? ''], 
      ['Espécie:', dados.beneficio.especie ?? ''],
      ['DIB:', dados.beneficio.dib ?? ''],
      ['DCB:', dados.beneficio.dcb ?? ''],
      ['DIP:', dados.beneficio.dip ?? ''],
      ['RM:', dados.beneficio.rm ?? '']
  ];

  const pagamentos: [number, number][] = []
  let novaPagina: TTabela<TCelula> = []
  let competenciaInicial, competenciaFinal

  if (Array.isArray(dados.pagamentos) && dados.pagamentos.length > 0) {
    competenciaInicial = dados.pagamentos[0].competencia.competencia(); 
    competenciaFinal = dados.pagamentos[dados.pagamentos.length - 1].competencia.competencia();
    
    const competencias = intervaloCompetencias(competenciaInicial, competenciaFinal);
    
    novaPagina.push(['Competência', 'Data Inicial', 'Data Final', 'Valor Líquido', 'Data Pagamento', 'Cód. 101', 'Cód. 104',
    'Cód. 105', 'Cód. 110', 'Cód. 137', 'Cód. 215', 'Cód. 316', 'Cód. 337']);
    
    competencias.forEach(competencia => {
      let pagamento;
      for (let i = 0; i < dados.pagamentos.length; i++) {
        const item = dados.pagamentos[i]
        if (item.competencia.igualA(competencia)) {
          pagamento = item
          break;
        }
      }
      if (pagamento) {
        pagamentos.push(dadosDesconto(pagamento))
        const primeiraParte = [competencia, pagamento.dataInicial, pagamento.dataFinal, pagamento.valorLiquido, pagamento.dataPagamento]
        const segundaParte = dadosNovaPagina(pagamento)
        novaPagina.push(Array.prototype.concat(primeiraParte, segundaParte))
      } else {
        pagamentos.push([0, 0])
        novaPagina.push([competencia, '', '', '', '', 0, 0, 0, 0, 0, 0, 0, 0])
      }
    });
  }

 novaPagina = concatenarTabelas(info, novaPagina)

 const resumo: TResumoHiscre = [
  ['Segurado(a):', dados.beneficio.segurado],
  ['NB:', dados.beneficio.nb],
  ['Dados:', `${pagamentos.filter(pagamento => Math.max(...pagamento) > 0).length} pagamentos encontrados`]
]

  return { resumo, pagamentos, novaPagina, competenciaInicial, competenciaFinal }
}

